Here is a simple example of implementing coroutines in C# without using Unity libraries:

```csharp
using System;
using System.Collections;

class CoroutineExample
{
    static void Main()
    {
        CoroutineManager coroutineManager = new CoroutineManager();
        coroutineManager.StartCoroutine(SimpleCoroutine());
        Console.WriteLine("Main method continues while coroutine is running.");

        while (coroutineManager.Update())
        {
            // Main loop continues while the coroutine is running
        }

        Console.WriteLine("Coroutine has finished.");
    }

    static IEnumerator SimpleCoroutine()
    {
        Console.WriteLine("Coroutine started.");
        yield return new WaitForSeconds(2); // Wait for 2 seconds
        Console.WriteLine("Coroutine finished.");
    }
}

class WaitForSeconds
{
    private readonly float _seconds;
    private DateTime _startTime;

    public WaitForSeconds(float seconds)
    {
        _seconds = seconds;
        _startTime = DateTime.Now;
    }

    public bool IsTimeUp => (DateTime.Now - _startTime).TotalSeconds >= _seconds;
}

class CoroutineManager
{
    private IEnumerator _currentCoroutine;

    public void StartCoroutine(IEnumerator coroutine)
    {
        _currentCoroutine = coroutine;
    }

    public bool Update()
    {
        if (_currentCoroutine != null && _currentCoroutine.MoveNext())
        {
            if (_currentCoroutine.Current is WaitForSeconds wait)
            {
                if (wait.IsTimeUp)
                {
                    return true;
                }
            }
            return true;
        }

        return false;
    }
}
```

In this example, we create a simple CoroutineManager class that can start coroutines and update them. We also define a SimpleCoroutine method as an example coroutine that prints messages and waits for 2 seconds using a custom WaitForSeconds class.
